import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface EventData {
  event: {
    name: string;
    date: string;
    daysRemaining: number;
    progress: number;
  };
}

export default function Widget() {
  const eventData = response.data as EventData;
  const { name, date, daysRemaining, progress } = eventData.event;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="#FFC107" fontWeight={600}>
              {name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Event Date: {date}
            </Typography>
          </Box>

          <Box>
            <Typography variant="h4" fontWeight={700} color="#FF5722">
              {daysRemaining} Days Remaining
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Progress
            </Typography>
            <LinearProgress
              variant="determinate"
              value={progress}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#424242',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FFC107',
                  borderRadius: 4,
                }
              }}
            />
            <Typography variant="caption" color="#FFC107" fontWeight={600}>
              {progress}%
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
